// ===== Theme Toggle =====
(function () {
  const storageKey = "nw-theme";
  const htmlEl = document.documentElement;
  const defaultTheme = "light";

  function applyTheme(theme) {
    htmlEl.setAttribute("data-bs-theme", theme);
    const icon = document.getElementById("themeIcon");
    if (icon) {
      icon.className =
        theme === "dark" ? "bi bi-sun-fill" : "bi bi-moon-stars-fill";
    }
  }

  function getSavedTheme() {
    try {
      return localStorage.getItem(storageKey) || defaultTheme;
    } catch {
      return defaultTheme;
    }
  }

  function saveTheme(theme) {
    try {
      localStorage.setItem(storageKey, theme);
    } catch {
      /* ignore */
    }
  }

  // Apply on page load
  const saved = getSavedTheme();
  applyTheme(saved);

  document.addEventListener("DOMContentLoaded", function () {
    applyTheme(getSavedTheme());

    const btn = document.getElementById("themeToggle");
    if (btn) {
      btn.addEventListener("click", function () {
        const current = htmlEl.getAttribute("data-bs-theme") || "light";
        const next = current === "dark" ? "light" : "dark";
        applyTheme(next);
        saveTheme(next);
      });
    }
  });
})();

// ===== Product price auto-fill on order detail page =====
document.addEventListener("DOMContentLoaded", function () {
  document.querySelectorAll(".nw-product-select").forEach(function (sel) {
    sel.addEventListener("change", function () {
      const opt = sel.options[sel.selectedIndex];
      const price = opt.dataset.price;
      const row = sel.closest("tr") || sel.closest(".nw-line-row");
      if (row && price) {
        const priceInput = row.querySelector(".nw-unit-price");
        if (priceInput) {
          priceInput.value = price;
          updateExtendedPrice(row);
        }
      }
    });
  });

  document
    .querySelectorAll(".nw-qty-input, .nw-unit-price")
    .forEach(function (inp) {
      inp.addEventListener("input", function () {
        const row = inp.closest("tr") || inp.closest(".nw-line-row");
        if (row) updateExtendedPrice(row);
      });
    });

  function updateExtendedPrice(row) {
    const qty = parseFloat(row.querySelector(".nw-qty-input")?.value) || 0;
    const price = parseFloat(row.querySelector(".nw-unit-price")?.value) || 0;
    const extEl = row.querySelector(".nw-extended-price");
    if (extEl) extEl.textContent = "$" + (qty * price).toFixed(2);
  }

  // Order total recalculation
  function recalcTotal() {
    let total = 0;
    document.querySelectorAll(".nw-line-extended-val").forEach(function (el) {
      total += parseFloat(el.textContent.replace("$", "")) || 0;
    });
    const totalEl = document.getElementById("orderTotal");
    if (totalEl) totalEl.textContent = "$" + total.toFixed(2);
  }

  document
    .querySelectorAll(".nw-qty-input, .nw-unit-price")
    .forEach(function (inp) {
      inp.addEventListener("input", recalcTotal);
    });

  // Confirm destructive actions
  document.querySelectorAll("[data-confirm]").forEach(function (el) {
    el.addEventListener("click", function (e) {
      if (!confirm(el.dataset.confirm)) e.preventDefault();
    });
  });
});
